import{_ as a,o as e,c as i,O as t}from"./chunks/framework.bdcb0ee1.js";const b=JSON.parse('{"title":"Social Login","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/social-login.md","filePath":"administration/users/social-login.md","lastUpdated":1773167323000}'),o={name:"administration/users/social-login.md"},r=t('<h1 id="social-login" tabindex="-1">Social Login <a class="header-anchor" href="#social-login" aria-label="Permalink to &quot;Social Login&quot;">​</a></h1><p>Social login allows users to easily authenticate into ForumSpark using their preferred provider. Users can choose to link 1 or more providers once they have been configured in the admin.</p><img width="1937" height="543" alt="image" src="https://github.com/user-attachments/assets/0a4ad88d-b5fe-4896-b15f-bc48aedab039"><nav class="table-of-contents"><ul><li><a href="#oauth-2-0">OAuth 2.0</a></li><li><a href="#create-a-login-app-with-3rd-party-services">Create a login app with 3rd party services</a><ul><li><a href="#discord">Discord</a></li><li><a href="#facebook">Facebook</a></li><li><a href="#github">GitHub</a></li><li><a href="#google">Google</a></li></ul></li><li><a href="#user-login">User Login</a></li></ul></nav><h2 id="oauth-2-0" tabindex="-1">OAuth 2.0 <a class="header-anchor" href="#oauth-2-0" aria-label="Permalink to &quot;OAuth 2.0&quot;">​</a></h2><p>Social Login uses an authentication mechanism called OAuth 2.0. In order to configure authentication with a 3rd party provider, you will need to create an OAuth app in the developer tools of your chosen integration.</p><p>From the admin area, choose &#39;Social Login&#39;.</p><p>From the list provided, choose the integration you wish to enable and then click &#39;Configure&#39;.</p><img width="1940" height="681" alt="image" src="https://github.com/user-attachments/assets/d8486aa8-a7fd-41b9-a660-32f0df5d24eb"><p>From the configuration page, you will be given a callback URL that you will need to paste into the 3rd party callback URL field. It will look something like <code>https://support.forumspark.net/social/discord/callback</code> - this is the URL that the user is redirected to once they have confirmed their login with the 3rd party service.</p><p>Once you have an app, you&#39;ll be able to use its client id and secret and paste those into the ForumSpark admin:</p><h2 id="create-a-login-app-with-3rd-party-services" tabindex="-1">Create a login app with 3rd party services <a class="header-anchor" href="#create-a-login-app-with-3rd-party-services" aria-label="Permalink to &quot;Create a login app with 3rd party services&quot;">​</a></h2><p>This section will describe where and how to set up each 3rd party integration.</p><h3 id="discord" tabindex="-1">Discord <a class="header-anchor" href="#discord" aria-label="Permalink to &quot;Discord&quot;">​</a></h3><h3 id="facebook" tabindex="-1">Facebook <a class="header-anchor" href="#facebook" aria-label="Permalink to &quot;Facebook&quot;">​</a></h3><h3 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h3><h3 id="google" tabindex="-1">Google <a class="header-anchor" href="#google" aria-label="Permalink to &quot;Google&quot;">​</a></h3><h2 id="user-login" tabindex="-1">User Login <a class="header-anchor" href="#user-login" aria-label="Permalink to &quot;User Login&quot;">​</a></h2><p>Once you have enabled a service, it will automatically appear on the user login screen.</p>',19),l=[r];function s(n,h,c,d,u,p){return e(),i("div",null,l)}const m=a(o,[["render",s]]);export{b as __pageData,m as default};
